import fs from"fs";import path from"path";import{exec}from"child_process";import{fileURLToPath}from"url";const __filename=fileURLToPath(import.meta.url),__dirname=path.dirname(__filename),folder=__dirname;fs.readdir(folder,(e,r)=>{e?console.error("Error reading folder:",e):r.forEach(e=>{const r=path.extname(e),o=path.basename(e,r);if(".css"===r&&!e.endsWith(".min.css")){const r=e,i=`${o}.min.css`;exec(`npx cleancss -o "${i}" "${r}"`,(e,o,n)=>{e?console.error(`Error minifying ${r}:`,n):console.log(`Minified CSS: ${r} -> ${i}`)})}if(".js"===r&&!e.endsWith(".min.js")){const r=e,i=`${o}.min.js`;exec(`npx terser "${r}" -o "${i}" --compress --mangle`,(e,o,n)=>{e?console.error(`Error minifying ${r}:`,n):console.log(`Minified JS: ${r} -> ${i}`)})}})});